def kosaraju(V, adj):
    stack = []
    visited = [False] * V

    def dfs1(u):
        visited[u] = True
        for v in adj[u]:
            if not visited[v]: dfs1(v)
        stack.append(u)

    def dfs2(u, component, adj_t):
        visited[u] = True
        component.append(u)
        for v in adj_t[u]:
            if not visited[v]: dfs2(v, component, adj_t)

    # First pass
    for i in range(V):
        if not visited[i]: dfs1(i)

    # Transpose
    adj_t = [[] for _ in range(V)]
    for u in range(V):
        for v in adj[u]: adj_t[v].append(u)

    # Second pass
    visited = [False] * V
    sccs = []
    while stack:
        u = stack.pop()
        if not visited[u]:
            component = []
            dfs2(u, component, adj_t)
            sccs.append(component)
    return sccs

